<script>
    import $ from 'jquery'
    import { TweenMax } from 'gsap';
    import subFooter from '../component/sub-footer.vue'

    export default {
        components: { subFooter },

        methods: {

        },
        beforeRouteEnter (to, from ,next) {
            // 현재 컴포넌트 불러오기 전 menu close motion
            // menu 모션이 끝났을 때
            if ($('.menu-component').attr('_move') == 'false' || $('.menu-component').attr('_move') == undefined) {
                next();
            } else { // menu 모션이 끝나기 전
                return false;
            }
        },
        mounted () {
            worksEvent().init();
        },
    }

    var worksEvent = function () {
        var $scrollLeftFunc, $list, $setWidth;

        function init () {
            $setWidth = $('.container').width() + 100;
            $list = $('.works-list .list-wrap');

            // set width scroll el of work list 
            $list.css('width', $setWidth);

            // active scroll funtion
            $scrollLeftFunc = new ScrollLeftFunction();
            $scrollLeftFunc.active($(window), $list);

            bindEvent();
        }

        function bindEvent () {
            $(window).on('resize', function () {
                // init
                $setWidth = $('.container').width() + 100;
                $list.css('width', $setWidth);

                $scrollLeftFunc.destory($(window));

                setTimeout(function () {
                    $scrollLeftFunc.active($list);
                }, 0)
            })

            $('.works-list .list').on('click', function (e) {
                e.preventDefault();

                var _this = $(this);
                var _thisIndex = _this.index();

                openPopup($('.popup').eq(_thisIndex));
            })

            $('.popup-close').on('click', function () {
                var _this = $(this);
                var _thisPopup = _this.parents('.popup');
                closePopup(_thisPopup);
            })
        }

        function openPopup (_openEl) {
            _openEl.show();
            $('.dimm').show();
            setCenterPopup(_openEl);
        }

        function closePopup (_closeEl) {
            _closeEl.hide();
            $('.dimm').hide();
        }

        function setCenterPopup (_moveEl) {
            _moveEl.css({
                'top':'50%',
                'left':'50%',
                'margin-left': - _moveEl.width() / 2,
                'margin-top': - _moveEl.height() / 2,
            })
        }

        return {
            init : init
        }
    }

    var ScrollLeftFunction = function () {
        var $el, $moveLeft, $rangeEl;
        // var $upDown;

        this.init = (function () {
            $moveLeft = 0;
        })();

        this.active = function (_rangeEl, _el) {
            $rangeEl = $(_rangeEl);
            $el = $(_el);

            $rangeEl.on("mousewheel DOMMouseScroll", function(event){
                var _wheelDelta = event.originalEvent.wheelDelta;
        
                if (!event) event = window.event;
                // if(event.originalEvent.wheelDelta > 0) {
                //     $upDown = "up";
                // } else {
                //     $upDown = "down";
                // }
        
                render(_wheelDelta);
            })
        }

        this.destory = function (_rangeEl) {
            $rangeEl = $(_rangeEl);

            $rangeEl.off("mousewheel DOMMouseScroll");
        }

        function render(_wheelDelta){
            $moveLeft -= _wheelDelta;
            if($moveLeft < 0) $moveLeft = 0;

            moveLeftFunc();
        }

        function moveLeftFunc () {
            TweenMax.to($el, 0.5, {
                scrollLeft: $moveLeft,
                onUpdate:function(){
                    
                }, 
            });
        }   
	}

</script>

