<script>
    import $ from 'jquery'
    // import { TweenMax , Expo } from 'gsap';
    import ScrollMagic from 'scrollmagic';

    import subFooter from '../component/sub-footer.vue'


    export default {
        components: { subFooter },

        methods: {

        },
        beforeRouteEnter (to, from ,next) {
            // 현재 컴포넌트 불러오기 전 menu close motion
            // menu 모션이 끝났을 때
            if ($('.menu-component').attr('_move') == 'false' || $('.menu-component').attr('_move') == undefined) {
                next();
            } else { // menu 모션이 끝나기 전
                return false;
            }
        },
        mounted () {
            profileEvent().init();
        },
    }

    var profileEvent = function () {
        var explain, explainSubTit, accorBtn, offset;

        function init () {
            explain = $('.page-explain');
            explainSubTit = explain.find('.sub-title');
            accorBtn = $('.accordion button');
            offset = $('.page-content').offset().top / 2.5;

            // intro motion
            // init
            // $('.page-explain > .title').css('visibility','hidden');

            // scroll
            setScrollMagic();

            // 1st motion
            // setTimeout(introMotion, 800);

            bindEvent();
        }

        function bindEvent () {
            // accor click
            accorBtn.on('click', function () {
                var _this = $(this);

                if (!_this.hasClass('on')) {
                    openAccordion(_this);
                } else {
                    closeAccordion(_this);
                }
            })
        }

        // 1st motion
        // function introMotion () {
        //     $('.page-explain > .title').css('visibility','visible');
        //     $('.page-explain > .title').addClass('on');
        // }

        function setScrollMagic () {
            var controller = new ScrollMagic.Controller({globalSceneOptions: {triggerHook: "onLeave"}});
            var scene = new ScrollMagic.Scene({offset: 0, duration: offset})
                                    .setPin(".page-explain", {pushFollowers: false})
                                    .addTo(controller);

            scene.on('leave', function () {
                $('.scrollmagic-pin-spacer').removeAttr('style');

                explainSubTit.addClass('on');
            });

            scene.on('enter', function () {
                explainSubTit.removeClass('on');
            })
        }

        function openAccordion (_this) {
            _this.addClass('on');
            _this.next('.acc-panel').slideDown(350);
        }

        function closeAccordion (_this) {
            _this.removeClass('on');
            _this.next('.acc-panel').slideUp(350);
        }

        return {
            init : init
        }
    }

</script>

